// Zip parallel arrays into one item per listing
const j = $input.first().json;
const n = (j.title || []).length;
const out = [];
for (let i = 0; i < n; i++) {
  out.push({ json: { title: j.title[i], price: j.price?.[i], url: j.url?.[i] } });
}
return out;

